const inputData = $('Filtrar_Candidatos').item.json;
const candidates = inputData.candidates_raw;
const allResults = inputData.all_results;

try {
  const cleanText = $json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const data = JSON.parse(cleanText);
  const selectedIndices = data.indices || [];

  const relevantResults = selectedIndices.map(i => candidates[i]).filter(Boolean);
  if (relevantResults.length === 0 && candidates.length > 0) {
    relevantResults.push(candidates[0]);
  }

  const seen = new Set();
  const sourceUrls = [], pageNumbers = [], excludeIds = allResults.map(r => r.id).filter(Boolean);

  for (const r of relevantResults) {
    const src = r.metadata?.source_url || '';
    const pn = r.metadata?.page_number || 0;
    const key = `${src}|${pn}`;
    if (src && !seen.has(key)) {
      seen.add(key);
      sourceUrls.push(src);
      pageNumbers.push(pn);
    }
  }

  return [{ json: {
    originalResults: allResults,
    relevantResults: relevantResults,
    needsExpansion: sourceUrls.length > 0,
    expansionParams: {
      p_source_urls: sourceUrls,
      p_page_numbers: pageNumbers,
      p_exclude_ids: excludeIds,
      p_window: 1
    }
  } }];
} catch (e) {
  return [{ json: {
    originalResults: allResults,
    relevantResults: [candidates[0]],
    needsExpansion: !!candidates[0],
    expansionParams: {
      p_source_urls: candidates[0]?.metadata?.source_url ? [candidates[0].metadata.source_url] : [],
      p_page_numbers: candidates[0]?.metadata?.page_number ? [candidates[0].metadata.page_number] : [],
      p_exclude_ids: allResults.map(r => r.id).filter(Boolean),
      p_window: 1
    }
  } }];
}

const selectionData = $('Procesar_Seleccion').item.json;
const initialResults = selectionData.originalResults || [];
const relevantResults = selectionData.relevantResults || [];
const input = $('Extraer_Plan').item.json;
let adjacentChunks = [];
try { adjacentChunks = $('Supabase_Adjacent').all().map(i => i.json).filter(r => r && r.id); } catch (_) { adjacentChunks = []; }
if (initialResults.length === 0 && (adjacentChunks.length === 0 || !adjacentChunks[0]?.id)) {
  return [{ json: { contexto: '', images: [], sourceUrl: '', sinResultados: true, chat_id: input.chat_id, query: input.query } }];
}
const seenContent = new Set();
const dedup = (arr) => arr.filter(r => { const key = (r.content || '').trim(); if (!key || seenContent.has(key)) return false; seenContent.add(key); return true; });
const textResults = dedup(relevantResults).filter(r => r.type === 'text');
const imageResults = dedup(relevantResults).filter(r => r.type === 'image');
const allTextChunks = [...textResults, ...dedup(adjacentChunks).filter(r => r.type === 'text')];
const grouped = {}, groupMeta = {};
for (const chunk of allTextChunks) {
  const src = chunk.metadata?.source_url || 'unknown';
  if (!grouped[src]) { grouped[src] = []; groupMeta[src] = { manual_name: chunk.metadata?.manual_name || '', article_title: chunk.metadata?.article_title || '', contextual_header: chunk.metadata?.contextual_header || '' }; }
  grouped[src].push({ content: chunk.content, _pn: chunk.metadata?.page_number || 0, _ci: chunk.metadata?.chunk_index || 0 });
}
const contextParts = [];
for (const [src, chunks] of Object.entries(grouped)) {
  chunks.sort((a, b) => a._pn - b._pn || a._ci - b._ci);
  const meta = groupMeta[src];
  const headerParts = [meta.manual_name, meta.article_title, meta.contextual_header].filter(Boolean);
  const headerLine = headerParts.length > 0 ? '[' + headerParts.join(' › ') + ']\n' : '';
  contextParts.push(headerLine + chunks.map(c => c.content).join('\n'));
}
const contexto = contextParts.join('\n\n---\n\n');
const images = imageResults.map((r, i) => ({ index: i+1, filename: r.metadata?.image_filename || ('imagen_'+(i+1)+'.jpg'), base64: r.metadata?.original_content || null, sourceUrl: r.metadata?.source_url || '' })).slice(0, 4);
const mainSourceUrl = relevantResults[0]?.metadata?.source_url || initialResults[0]?.metadata?.source_url || '';
return [{ json: { contexto, images, sourceUrl: mainSourceUrl, sinResultados: false, chat_id: input.chat_id, query: input.query } }];

const { contexto, images, query, sourceUrl, chat_id } = $json;
const hasImage = !!$('input').item.json.image_base64;
const imageData = $('input').item.json.image_base64 || null;
const imageMimeType = $('input').item.json.image_mime_type || 'image/jpeg';
const vars = $('Get_Variables').item.json;
const userName = vars.Usuario?.name || vars.Usuario?.userName || 'Usuario';
const fecha = new Date().toLocaleDateString('es-MX', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const imageListForPrompt = images && images.length > 0
  ? '\n\nIMÁGENES TÉCNICAS DISPONIBLES EN EL MANUAL:\n' + images.map(img => '  [' + img.index + '] ' + img.filename).join('\n') + '\nSi el usuario solicita visuales o si una imagen ayuda a explicar, inclúyela usando: [ENVIAR_IMAGENES: N].'
  : '';

const systemInstruction = `FECHA ACTUAL: ${fecha}
Eres SARA, la asistente técnica experta de Satcom. Tu objetivo es resolver dudas del usuario utilizando la documentación técnica proporcionada.

INSTRUCCIONES DE CONOCIMIENTO:
1. Se te entregará información bajo 'DOCUMENTACIÓN DE APOYO'. Este es tu conocimiento interno. NO agradezcas al usuario por esta información.
2. Responde directamente a la consulta del usuario basándote en dicha documentación.
3. Si la respuesta no está en la documentación, indícalo de forma profesional.
4. Estás hablando con ${userName}.

REGLAS DE FORMATO:
- Si recibes una imagen del usuario, analízala para complementar tu respuesta.
- Cita la fuente (Manual/Sección) solo cuando la respuesta provenga de la documentación.
- Para imágenes del manual que aporten valor: [ENVIAR_IMAGENES: N].
- NO inventes información. Si no sabes algo, admítelo.`;

const userParts = [];
if (hasImage) userParts.push({ inline_data: { mime_type: imageMimeType, data: imageData } });

let fullPrompt;
if (contexto) {
  fullPrompt = `DOCUMENTACIÓN DE APOYO (Tu base de conocimientos):
${contexto}
${imageListForPrompt}

________________________________
CONSULTA DEL USUARIO:
${query}`;
} else {
  fullPrompt = query;
}

userParts.push({ text: fullPrompt });

return [{ json: {
  gemini_body: {
    system_instruction: { parts: [{ text: systemInstruction }] },
    contents: [{ role: 'user', parts: userParts }],
    generationConfig: { temperature: 0.1, maxOutputTokens: 2048 }
  },
  images: images || [],
  sourceUrl: sourceUrl || '',
  chat_id
} }];

const preparador = $('Preparar_Body_LLM').item.json;
const imagesFromRAG = preparador.images || [];
const sourceUrl = preparador.source_url || preparador.sourceUrl || '';
const chat_id = preparador.chat_id || $('input').item.json.chat_id;
let finalResponse = $json.output || '';
if (!finalResponse) {
  return [{ json: { chat_id, final_response: 'SARA generó una respuesta vacía. Por favor reformula tu pregunta.', source_url: sourceUrl, send_image: false } }];
}
const regex = /\[ENVIAR_IMAGENES:\s*([\d,\s]+)\]/i;
const match = finalResponse.match(regex);
let imageToSend = null;
if (match && imagesFromRAG.length > 0) {
  const indices = match[1].split(',').map(s => parseInt(s.trim())).filter(n => !isNaN(n));
  for (const idx of indices) {
    const img = imagesFromRAG[idx - 1];
    if (img && img.base64) { imageToSend = img.base64; break; }
  }
  finalResponse = finalResponse.replace(regex, '').trim();
}
const output = { json: { chat_id, final_response: finalResponse, source_url: sourceUrl, send_image: !!imageToSend } };
if (imageToSend) { output.binary = { data: { data: imageToSend, mimeType: 'image/jpeg', fileName: 'imagen_manual.jpg' } }; }
return [output];

const data = $('Procesar_Output').first().json;
const response = data.final_response || 'No encontré información relevante en los manuales.';
const sourceUrl = data.source_url || '';
const withLink = sourceUrl ? `${response}\n\n🔗 [Ver en el Manual Original](${sourceUrl})` : response;
return [{ json: { response: withLink } }];
